import React from 'react';
import { formatDate } from '../data/bookingData.js';
import styles from '../styles/ConfirmationPage.module.css';

const BOOKING_META = {
  dayUse: {
    label: 'Day Use',
    icon: '☀️',
    hours: '8:00 AM – 8:00 PM',
    arrivalNote: 'Check-in starts at 8:00 AM · Please bring a valid ID',
  },
  overnight: {
    label: 'Overnight',
    icon: '🌙',
    hours: '2:00 PM – 11:00 AM (next day)',
    arrivalNote: 'Check-in starts at 2:00 PM · Please bring a valid ID',
  },
};

const ConfirmationPage = ({ data, onNewBooking }) => {
  if (!data) return null;

  const {
    bookingType, checkIn, guests,
    guestName, guestContact, contactMethod,
    specialRequests, total, refCode,
  } = data;

  const meta = BOOKING_META[bookingType] ?? BOOKING_META.dayUse;
  const isEmail = contactMethod === 'email';
  const contactLabel = isEmail ? 'Email' : 'Messenger';
  const contactDisplay = isEmail
    ? guestContact
    : (
      <a
        href={guestContact.startsWith('http') ? guestContact : `https://${guestContact}`}
        target="_blank"
        rel="noopener noreferrer"
        className={styles.messengerLink}
      >
        {guestContact}
      </a>
    );

  return (
    <div className={styles.page}>
      <div className={styles.container}>

        <div className={styles.successBadge}>
          <div className={styles.successIcon}>✦</div>
          <span className={styles.successLabel}>Reservation Confirmed</span>
        </div>

        <div className={styles.card}>
          <div className={styles.cardHeader}>
            <span className={styles.kanji}>ありがとう</span>
            <div>
              <h1 className={styles.title}>Thank you, {guestName.split(' ')[0]}!</h1>
              <p className={styles.subtitle}>Your stay at Mizuya Exclusive Resort has been reserved.</p>
            </div>
          </div>

          <div className={styles.refRow}>
            <span className={styles.refLabel}>Reference Code</span>
            <span className={styles.refCode}>{refCode}</span>
          </div>

          <div className={styles.detailsGrid}>
            {/* Booking type */}
            <div className={`${styles.detailBlock} ${styles.fullWidth}`}>
              <span className={styles.detailLabel}>Booking Type</span>
              <span className={styles.detailValue}>
                {meta.icon} {meta.label}
              </span>
              <span className={styles.detailNote}>{meta.hours}</span>
            </div>

            {/* Date */}
            <div className={styles.detailBlock}>
              <span className={styles.detailLabel}>Date</span>
              <span className={styles.detailValue}>{formatDate(checkIn)}</span>
              <span className={styles.detailNote}>{meta.arrivalNote}</span>
            </div>

            {/* Guests */}
            <div className={styles.detailBlock}>
              <span className={styles.detailLabel}>Guests</span>
              <span className={styles.detailValue}>{guests} guest{guests !== 1 ? 's' : ''}</span>
              {guests > 15 && (
                <span className={styles.detailNote}>
                  Includes ₱{((Math.min(guests - 15, 15)) * 250).toLocaleString()} extra guest fee
                </span>
              )}
            </div>

            {/* Contact */}
            <div className={styles.detailBlock}>
              <span className={styles.detailLabel}>{contactLabel}</span>
              <span className={styles.detailValue}>{contactDisplay}</span>
            </div>

            {/* Total */}
            <div className={styles.detailBlock}>
              <span className={styles.detailLabel}>Total Amount</span>
              <span className={`${styles.detailValue} ${styles.totalVal}`}>
                ₱{total.toLocaleString()}
              </span>
              <span className={styles.detailNote}>VAT inclusive · Pay upon arrival</span>
            </div>

            {/* Special requests */}
            {specialRequests && (
              <div className={`${styles.detailBlock} ${styles.fullWidth}`}>
                <span className={styles.detailLabel}>Special Requests</span>
                <span className={styles.detailNote}>{specialRequests}</span>
              </div>
            )}
          </div>

          <div className={styles.notice}>
            <span className={styles.noticeIcon}>🌸</span>
            {isEmail ? (
              <p>
                A confirmation email will be sent to <strong>{guestContact}</strong>.
                For inquiries, contact us at <strong>reservations@mizuya.ph</strong>
              </p>
            ) : (
              <p>
                Our team will reach out to you via Messenger at <strong>{guestContact}</strong>.
                For inquiries, contact us at <strong>reservations@mizuya.ph</strong>
              </p>
            )}
          </div>
        </div>

        <button className={styles.newBookingBtn} onClick={onNewBooking} type="button">
          ← Make Another Reservation
        </button>
      </div>
    </div>
  );
};

export default ConfirmationPage;
